function solve(nums) {
    const n = nums.length;
    if (n === 0) {
        return [];
    }

    const isLeftMax = new Array(n).fill(true);
    const isRightMax = new Array(n).fill(true);

    // Calculate isLeftMax: nums[i] must be strictly greater than all elements to its left
    // Since nums[0] is always valid, we check from i=1
    for (let i = 1; i < n; i++) {
        // If nums[i-1] is greater than or equal to nums[i], then nums[i] cannot be strictly greater than all elements to its left.
        // More precisely, we need to check if nums[i] > max(nums[0]...nums[i-1])

        // We can maintain the running maximum from the left
        let currentMax = -Infinity;
        for(let j = 0; j < i; j++) {
            if (nums[j] >= nums[i]) {
                isLeftMax[i] = false;
                break;
            }
        }
    }

    // Recalculating isLeftMax more efficiently (since we only need to check against the running max)
    // Let's re-think the definition for isLeftMax[i]: nums[i] > nums[j] for all j < i.
    isLeftMax.fill(true);
    let currentMaxLeft = nums[0];
    for (let i = 1; i < n; i++) {
        if (nums[i] <= currentMaxLeft) {
            isLeftMax[i] = false;
        } else {
            currentMaxLeft = nums[i];
        }
    }
    // Note: The first element is always true, which is handled by initialization/loop start.

    // Calculate isRightMax: nums[i] must be strictly greater than all elements to its right
    // Since nums[n-1] is always valid, we check from i=n-2 down to 0
    isRightMax.fill(true);
    let currentMaxRight = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] <= currentMaxRight) {
            isRightMax[i] = false;
        } else {
            currentMaxRight = nums[i];
        }
    }

    const result = [];
    for (let i = 0; i < n; i++) {
        // Condition for an element to be valid:
        // 1. Strictly greater than its left neighbors (handled by isLeftMax) OR
        // 2. Strictly greater than its right neighbors (handled by isRightMax)
        // WAIT: The problem states:
        // "If element nums[i] satisfies AT LEAST ONE condition:"
        // Condition A: strictly greater than its left side elements.
        // Condition B: strictly greater than its right side elements.
        // "The first element and the last element are always valid."

        let isValid = false;

        if (i === 0 || i === n - 1) {
            isValid = true; // Always valid
        } else {
            // Check Condition A: nums[i] > max(nums[0]...nums[i-1])
            let greaterThanLeft = true;
            for (let j = 0; j < i; j++) {
                if (nums[i] <= nums[j]) {
                    greaterThanLeft = false;
                    break;
                }
            }

            // Check Condition B: nums[i] > max(nums[i+1]...nums[n-1])
            let greaterThanRight = true;
            for (let j = i + 1; j < n; j++) {
                if (nums[i] <= nums[j]) {
                    greaterThanRight = false;
                    break;
                }
            }

            if (greaterThanLeft || greaterThanRight) {
                isValid = true;
            }
        }

        if (isValid) {
            result.push(nums[i]);
        }
    }

    return result;
}

